sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below

//KT - STRY0050725: Updated during REQ implementation
var errorMessage = 'Request ' + current.number + ' did not meet the conditions to provide Clarification';

if (current.u_request_type == "Clarification" &&
	current.parent.u_clarification_requested == true) {

	var taskWorkNotes = 'Clarification Request has been provided by ' + gs.getUserDisplayName() +
	' with the following comments: ' + current.u_response_comments;

	//KT: Update Task table
	var parentId = current.parent.toString();
	var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
	if (grTask.get(parentId)){

		var allow = new uiConditionCheck().RespondClarification(grTask);

		if (allow) {
			grTask.u_clarification_requested = false;
			grTask.work_notes = taskWorkNotes;
			grTask.update();

			//KT: Update Request table
			var todaysDate = new GlideDateTime();
			current.u_status = 'Completed'; //'Approved';
			current.u_response = 'Provided';
			current.u_responded_by = gs.getUserID();
			current.u_responded = todaysDate;
			current.update();

			//KT: Show Confirmation Message
			gs.addInfoMessage(taskWorkNotes);

			//-------
			//get the person who is going to receive
			var clarificationProvider = gs.getUserDisplayName().toString();
			var recipient = current.getValue('u_requested_by').toString();

			gs.eventQueue('x_153465_discovert.NotifClarificationPro', grTask, clarificationProvider, recipient);
			//-------

		} else gs.addErrorMessage(errorMessage);
	}

} else gs.addErrorMessage(errorMessage);
